class Solution {
public:
    int minChanges(int n, int k) {
        if ((n & k) != k) return -1;
        int changes = 0;
        while (n || k) {
            if (n & 1 && !(k & 1)) changes++;
            n >>= 1;
            k >>= 1;
        }
        return changes;
    }
};
```
